def analyze_string(text):
    result = {"letters": 0, "digits": 0, "spaces": 0, "other": 0}
    for char in text:
        if char.isalpha():
            result["letters"] += 1
        elif char.isdigit():
            result["digits"] += 1
        elif char == " ":
            result["spaces"] += 1
        else:
            result["other"] += 1
    return result

testCode:
def test_analyze_mixed():
    result = analyze_string("Hello World 123!")
    assert result == {"letters": 10, "digits": 3, "spaces": 2, "other": 1}

def test_analyze_only_letters():
    result = analyze_string("Python")
    assert result == {"letters": 6, "digits": 0, "spaces": 0, "other": 0}

def test_analyze_empty():
    result = analyze_string("")
    assert result == {"letters": 0, "digits": 0, "spaces": 0, "other": 0}

def test_analyze_special():
    result = analyze_string("!@#$")
    assert result == {"letters": 0, "digits": 0, "spaces": 0, "other": 4}

def test_analyze_spaces_only():
    result = analyze_string("   ")
    assert result == {"letters": 0, "digits": 0, "spaces": 3, "other": 0}

def test_analyze_digits():
    result = analyze_string("5 4 3 2 1")
    assert result == {"letters": 0, "digits": 5, "spaces": 4, "other": 0}

