def compute_stats(numbers):
    if not numbers:
        return {
            "count": 0,
            "total": 0,
            "average": 0.0,
            "large_numbers": [],
            "contains_negative": False
        }
    count = 0
    total = 0
    contains_negative = False
    for value in numbers:
        count = count + 1
        total = total + value
        if value < 0:
            contains_negative = True
    average = total / count
    large_numbers = []
    for value in numbers:
        if value > average:
            large_numbers.append(value)
    return {
        "count": count,
        "total": total,
        "average": average,
        "large_numbers": large_numbers,
        "contains_negative": contains_negative
    }

