def analyze_numbers(numbers):
    if len(numbers) == 0:
        result = {
            "count_positive": 0,
            "count_negative": 0,
            "count_zero": 0,
            "max": None,
            "min": None,
            "classification": "empty"
        }
        return result

    count_positive = 0
    count_negative = 0
    count_zero = 0
    max_val = numbers[0]
    min_val = numbers[0]

    for num in numbers:
        if num > 0:
            count_positive = count_positive + 1
        else:
            if num < 0:
                count_negative = count_negative + 1
            else:
                count_zero = count_zero + 1

        if num > max_val:
            max_val = num
        if num < min_val:
            min_val = num

    if count_positive > 0 and count_negative == 0 and count_zero == 0:
        classification = "all positive"
    else:
        if count_negative > 0 and count_positive == 0 and count_zero == 0:
            classification = "all negative"
        else:
            if count_zero == len(numbers):
                classification = "all zeros"
            else:
                classification = "mixed"

    result = {
        "count_positive": count_positive,
        "count_negative": count_negative,
        "count_zero": count_zero,
        "max": max_val,
        "min": min_val,
        "classification": classification
    }
    return result

