def which_branch(x):
    if x < 10:
        return 1
    elif x < 30:
        return 2
    elif x < 20:
        return 3
    return 0

def evaluate_condition(x, operator, value):
    if operator == "<":
        return x < value
    elif operator == ">":
        return x > value
    elif operator == "<=":
        return x <= value
    elif operator == ">=":
        return x >= value
    return False


def count_reachable_branches(conditions, has_else=False):
    reachable = [False] * len(conditions)
    else_reachable = False

    for x in range(-1000, 1001):
        for i, (operator, value) in enumerate(conditions):
            earlier_matched = False
            for j in range(i):
                if evaluate_condition(x, conditions[j][0], conditions[j][1]):
                    earlier_matched = True
                    break
            if not earlier_matched and evaluate_condition(x, operator, value):
                reachable[i] = True
                break
        else:
            if has_else:
                else_reachable = True

    count = sum(reachable)
    if has_else and else_reachable:
        count += 1
    return count

def shipping_cost(weight, distance):
    if weight <= 0 or distance <= 0:
        return 0
    elif weight < 1 and distance < 50:
        return 5.0
    elif weight < 1:
        return 8.0
    elif weight < 5 and distance < 50:
        return 10.0
    elif weight < 5:
        return 15.0
    elif weight < 20:
        return 25.0
    else:
        return 50.0

