solution:
class MemoryTracker:
    def __init__(self):
        self.variables = {}
        self.history = []

    def assign(self, name: str, value):
        old_value = self.variables.get(name, None)
        self.variables[name] = value
        self.history.append({
            'variable': name,
            'old_value': old_value,
            'new_value': value
        })

    def get(self, name: str):
        if name not in self.variables:
            raise KeyError(f"Zmienna '{name}' nie istnieje")
        return self.variables[name]

    def increment(self, name: str, amount=1):
        old_value = self.get(name)
        new_value = old_value + amount
        self.assign(name, new_value)

    def get_history(self) -> list:
        return self.history

