class FloorConverter:
    def __init__(self):
        self.countries = {}

    def add_country(self, code, offset):
        self.countries[code] = offset

    def convert(self, floor_str, from_country, to_country):
        if from_country not in self.countries or to_country not in self.countries:
            return None
        try:
            floor = int(floor_str)
        except ValueError:
            return None
        neutral_floor = floor - self.countries[from_country]
        return neutral_floor + self.countries[to_country]

    def get_countries(self):
        return sorted(self.countries.keys())

