def process_commands(commands):
    result = []
    last_command = None
    i = 0
    while i < len(commands):
        cmd = commands[i]
        i += 1
        if cmd == "" or cmd.startswith("#"):
            continue
        if cmd == "quit" or cmd == "exit":
            break
        if cmd.startswith("repeat "):
            parts = cmd.split(" ", 1)
            if len(parts) == 2 and parts[1].isdigit() and last_command is not None:
                n = int(parts[1])
                count = 0
                while count < n:
                    result.append(last_command)
                    count += 1
            continue
        result.append(cmd)
        last_command = cmd
    return result

