def text_calculator(expression):
    parts = expression.split()
    raw_a, operator, raw_b = parts[0], parts[1], parts[2]

    if '.' in raw_a:
        a = float(raw_a)
    else:
        a = int(raw_a)

    if '.' in raw_b:
        b = float(raw_b)
    else:
        b = int(raw_b)

    if operator == '+':
        return a + b
    elif operator == '-':
        return a - b
    elif operator == '*':
        return a * b
    elif operator == '/':
        if b == 0:
            return 'błąd: dzielenie przez zero'
        return a / b
    else:
        return 'błąd: nieznany operator'

