def evaluate_expression(a, b, c, d):
    return a + b ** c / d

def evaluate_with_parens(a, b, c, d):
    return (a + b) ** (c / d)

def evaluate_steps(expression_str):
    tokens = expression_str.split()
    numbers = []
    operators = []
    for token in tokens:
        if token in ('+', '-', '*', '/'):
            operators.append(token)
        else:
            numbers.append(float(token) if '.' in token else int(token))

    steps = []

    def tokens_to_str(nums, ops):
        parts = []
        for i, n in enumerate(nums):
            if isinstance(n, float) and n == int(n):
                parts.append(str(int(n)))
            else:
                parts.append(str(n))
            if i < len(ops):
                parts.append(ops[i])
        return ' '.join(parts)

    # Faza 1: * i /
    i = 0
    while i < len(operators):
        if operators[i] in ('*', '/'):
            if operators[i] == '*':
                result = numbers[i] * numbers[i + 1]
            else:
                result = numbers[i] / numbers[i + 1]
            numbers[i] = result
            numbers.pop(i + 1)
            operators.pop(i)
            steps.append(tokens_to_str(numbers, operators))
        else:
            i += 1

    # Faza 2: + i -
    while operators:
        if operators[0] == '+':
            result = numbers[0] + numbers[1]
        else:
            result = numbers[0] - numbers[1]
        numbers[0] = result
        numbers.pop(1)
        operators.pop(0)
        steps.append(tokens_to_str(numbers, operators))

    return steps

