import keyword

def is_valid_variable_name(name):
    if not name:
        return False
    if not (name[0].isalpha() or name[0] == '_'):
        return False
    for char in name[1:]:
        if not (char.isalnum() or char == '_'):
            return False
    if keyword.iskeyword(name):
        return False
    return True

