def trace_assignments(statements):
    variables = {}
    for stmt in statements:
        left, right = stmt.split('=')
        left = left.strip()
        right = right.strip()
        if '+' in right:
            parts = right.split('+')
            total = 0
            for part in parts:
                part = part.strip()
                if part.lstrip('-').isdigit():
                    total += int(part)
                else:
                    total += variables[part]
            variables[left] = total
        elif right.lstrip('-').isdigit():
            variables[left] = int(right)
        else:
            variables[left] = variables[right]
    return variables

