def loop_accumulate(numbers, operation):
    if operation == 'sum':
        total = 0
        for value in numbers:
            total += value
        return total
    elif operation == 'count':
        count = 0
        for value in numbers:
            count += 1
        return count
    elif operation == 'min':
        smallest = None
        for value in numbers:
            if smallest is None or value < smallest:
                smallest = value
        return smallest
    elif operation == 'max':
        largest = None
        for value in numbers:
            if largest is None or value > largest:
                largest = value
        return largest
    else:
        raise ValueError(f"Nieznana operacja: {operation}")

