def compute_stats(numbers: list[float]) -> dict:
    total = 0
    count = 0
    for num in numbers:
        total += num
        count += 1
    average = total / count if count > 0 else 0.0
    return {"total": total, "count": count, "average": average}

def count_and_collect(numbers: list[int], condition) -> tuple[int, list[int]]:
    count = 0
    matched = []
    for num in numbers:
        if condition(num):
            count += 1
            matched.append(num)
    return (count, matched)
